      {/* Order Detail Modal */}
      {renderOrderDetailModal()}

      {/* Sync Result Popup */}
      {renderSyncResultModal()}

      {/* Confirm Order Modal with Pickup Method */}
      {renderConfirmOrderModal()}

      {/* Process Order Modal */}
      {renderProcessOrderModal()}

    </div>
  );
};

