      const isLate = deadlineDate && deadlineDate < now;
      const isNearDeadline = deadlineDate && deadlineDate < new Date(now.getTime() + 24 * 60 * 60 * 1000) && !isLate;

      const isProcessed = order.subStatus === 'printed' || order.subStatus === 'packed';

